Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file.

```cpp
#include <iostream>
#include <fstream>
#include <sstream>
#include <string>

int countWordOccurrences(const std::string &word, const std::string &line) {
    int count = 0;
    std::istringstream iss(line);
    std::string currentWord;

    while (iss >> currentWord) {
        if (currentWord == word) {
            count++;
        }
    }

    return count;
}

int main() {
    std::string fileName;
    std::string targetWord;

    std::cout << "Enter the name of the text file: ";
    std::cin >> fileName;

    std::cout << "Enter the word to count occurrences: ";
    std::cin >> targetWord;

    std::ifstream file(fileName);
    std::string line;
    int totalOccurrences = 0;

    if (file.is_open()) {
        while (std::getline(file, line)) {
            totalOccurrences += countWordOccurrences(targetWord, line);
        }
        file.close();
    } else {
        std::cout << "Unable to open the file." << std::endl;
        return 1;
    }

    std::cout << "The word '" << targetWord << "' occurs " << totalOccurrences << " times in the file." << std::endl;

    return 0;
}
```

To run this program, save it to a file named "word_count.cpp" and compile it using a C++ compiler (e.g., g++), then run the resulting executable:

```
